package JAVA_DAY_3;

public class ELSEIF_CONDn {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		int marks = 80;
		if(marks >= 90)
		{
			System.out.println("A Grade");
		}
		else if(marks >= 75)
		{
			System.out.println("B Grade");
		}
		else
		{
			System.out.println("Fail");
		}

	}

}
